package kotlinx.coroutines

import kotlin.coroutines.*
import kotlin.test.*

/**
 * Tests for [CoroutineContext.isActive] extension property.
 */
class CoroutineContextIsActiveTest : TestBase() {

    @Test
    fun testEmptyContextIsActive() {
        // Empty context should be considered active since it has not been cancelled
        assertTrue(EmptyCoroutineContext.isActive)
    }

    @Test
    fun testContextWithoutJobIsActive() {
        // Context without Job should be considered active since it cannot be cancelled
        val context = CoroutineName("test")
        assertTrue(context.isActive)
    }

    @Test
    fun testContextWithActiveJobIsActive() {
        val job = Job()
        val context = job + CoroutineName("test")
        assertTrue(context.isActive)
        job.cancel()
    }

    @Test
    fun testContextWithCancelledJobIsNotActive() {
        val job = Job()
        job.cancel()
        val context = job + CoroutineName("test")
        assertFalse(context.isActive)
    }

    @Test
    fun testContextWithCompletedJobIsNotActive() {
        val job = Job()
        job.complete()
        val context = job + CoroutineName("test")
        assertFalse(context.isActive)
    }

    @Test
    fun testCoroutineScopeIsActiveConsistency() {
        // CoroutineScope.isActive and CoroutineContext.isActive should behave consistently
        // when there's no Job
        val scope = object : CoroutineScope {
            override val coroutineContext: CoroutineContext = EmptyCoroutineContext
        }
        assertEquals(scope.isActive, scope.coroutineContext.isActive)
    }

    @Test
    fun testWithEmptyContextIsActive() = runTest {
        withEmptyContext {
            // Within empty context, coroutineContext.isActive should be true
            assertTrue(coroutineContext.isActive)
        }
    }
}
"}

